#include <bits/stdc++.h>
using namespace std;
const int N=4e3+3;
const long long mod=2147483648;
int n,dp[N];
int main(){
    scanf("%d",&n);
    dp[0]=1;
    for(int i=1;i<=n;i++)
        for(int j=i;j<=n;j++)
            dp[j]=((long long)dp[j]+dp[j-i])%mod;
    printf("%lld",dp[n]-1);
    return 0;
}
